import { useEffect, useState } from "react";

function Dashboard() {
    const [threads, setThreads] = useState([]);
    const [news, setNews] = useState([]);
    const [matches, setMatches] = useState([]);
    const [events, setEvents] = useState([]);
    const [showThreads, setShowThreads] = useState(true);

    useEffect(() => {
        fetch("/api/threads").then(res => res.json()).then(setThreads);
        fetch("/api/news").then(res => res.json()).then(setNews);
        fetch("/api/matches").then(res => res.json()).then(data => {
            if (Array.isArray(data)) {
                setMatches(data);
            } else if (data.content) {
                setMatches(data.content);
            } else {
                setMatches([]);
            }
        }).catch(() => setMatches([]));
        fetch("/api/events").then(res => res.json()).then(setEvents);
    }, []);

    useEffect(() => {
        const handleResize = () => {
            if (window.innerHeight < 600) {
                setShowThreads(false);
            } else {
                setShowThreads(true);
            }
        };

        // Run once on mount
        handleResize();

        window.addEventListener("resize", handleResize);
        return () => window.removeEventListener("resize", handleResize);
    }, []);

    const boxStyle = {
        border: "1px solid #ccc",
        padding: "10px",
        marginBottom: "10px",
        borderRadius: "8px",
        cursor: "pointer",
        backgroundColor: "#fff",
        boxShadow: "0 4px 8px rgba(0, 0, 0, 0.1)",
        height: "30px",
        display: "flex",
        flexDirection: "column",
        justifyContent: "center",
        overflow: "hidden",
        transition: "transform 0.3s ease, box-shadow 0.3s ease, background-color 0.3s ease",
    };

    const handleMouseEnter = (e) => {
        e.currentTarget.style.backgroundColor = "#f0f4f8";
        e.currentTarget.style.transform = "translateY(-5px)";
        e.currentTarget.style.boxShadow = "0 8px 16px rgba(0, 0, 0, 0.2)";
    };

    const handleMouseLeave = (e) => {
        e.currentTarget.style.backgroundColor = "#fff";
        e.currentTarget.style.transform = "translateY(0)";
        e.currentTarget.style.boxShadow = "0 4px 8px rgba(0, 0, 0, 0.1)";
    };

    return (
        <main style={{ paddingTop: "40px", height: "100vh", overflowY: "auto" }}>
            <div style={{ display: "flex", gap: "20px" }}>
                {showThreads && (
                    <div style={{ flex: 1 }}>
                        <h3>Threads</h3>
                        {threads.map((thread, idx) => (
                            <div
                                key={idx}
                                onClick={() => alert(`Clicked thread: ${thread.title}`)}
                                style={boxStyle}
                                onMouseEnter={handleMouseEnter}
                                onMouseLeave={handleMouseLeave}
                            >
                                {thread.title}
                            </div>
                        ))}
                    </div>
                )}

                <div style={{ flex: 1 }}>
                    <h3>News</h3>
                    {news.map((item, idx) => (
                        <div
                            key={idx}
                            onClick={() => alert(`Clicked news: ${item.headline}`)}
                            style={boxStyle}
                            onMouseEnter={handleMouseEnter}
                            onMouseLeave={handleMouseLeave}
                        >
                            {item.headline}
                        </div>
                    ))}
                </div>

                <div style={{ flex: 1 }}>
                    <h3>Matches</h3>
                    {matches.map((match, idx) => (
                        <div
                            key={idx}
                            onClick={() => alert(`Clicked match: ${match.teama} vs ${match.teamb}`)}
                            style={boxStyle}
                            onMouseEnter={handleMouseEnter}
                            onMouseLeave={handleMouseLeave}
                        >
                            {match.teama} vs {match.teamb}
                            <br />
                            <small>{new Date(match.match_time).toLocaleString()}</small>
                        </div>
                    ))}
                </div>

                <div style={{ flex: 1 }}>
                    <h3>Events</h3>
                    {events.map((event, idx) => (
                        <div
                            key={idx}
                            onClick={() => alert(`Clicked event: ${event.name}`)}
                            style={boxStyle}
                            onMouseEnter={handleMouseEnter}
                            onMouseLeave={handleMouseLeave}
                        >
                            {event.name}
                            <br />
                            <small>{new Date(event.event_date_time).toLocaleString()}</small>
                        </div>
                    ))}
                </div>
            </div>
        </main>
    );
}

export default Dashboard;
